import {
  defineSignal,
  defineQuery,
  proxyActivities,
  setHandler,
  sleep,
} from '@temporalio/workflow';

export interface SubscriptionInput {
  userId: string;
  tier: string;
}

export interface SubscriptionStatus {
  tier: string;
  billings: number;
  cancelled: boolean;
}

export interface SubscriptionResult {
  billings: number;
  finalTier: string;
  cancelled: boolean;
}

const upgradeSignal = defineSignal<[string]>('upgrade');
const cancelSignal = defineSignal('cancel');
const getStatusQuery = defineQuery<SubscriptionStatus>('getStatus');

const { chargeCard } = proxyActivities<{
  chargeCard: (userId: string, tier: string) => Promise<void>;
}>({
  startToCloseTimeout: '1 minute',
});

export async function SubscriptionWorkflow(
  input: SubscriptionInput
): Promise<SubscriptionResult> {
  let tier = input.tier;
  let billings = 0;
  let cancelled = false;

  setHandler(upgradeSignal, (newTier) => {
    tier = newTier;
  });

  setHandler(cancelSignal, () => {
    cancelled = true;
  });

  setHandler(getStatusQuery, () => ({
    tier,
    billings,
    cancelled,
  }));

  for (let period = 0; period < 12; period += 1) {
    if (cancelled) {
      break;
    }

    await chargeCard(input.userId, tier);
    billings += 1;

    if (cancelled) {
      break;
    }

    await sleep(2000);
  }

  return {
    billings,
    finalTier: tier,
    cancelled,
  };
}

export const signals = {
  upgradeSignal,
  cancelSignal,
};

export const queries = {
  getStatusQuery,
};

import { promises as fs } from 'node:fs';

const chargesDir = '/workspace';
const chargesFile = `${chargesDir}/charges.log`;

export async function chargeCard(userId: string, tier: string): Promise<void> {
  await fs.mkdir(chargesDir, { recursive: true });
  await fs.appendFile(chargesFile, `${userId}:${tier}\n`, 'utf8');
}

import { NativeConnection, Worker } from '@temporalio/worker';
import * as activities from './activities.js';

const taskQueue = 'sub-ts';

export async function startWorker(): Promise<Worker> {
  const address = process.env.TEMPORAL_ADDRESS;
  const apiKey = process.env.TEMPORAL_API_KEY;
  const namespace = process.env.TEMPORAL_NAMESPACE;

  if (!address || !apiKey || !namespace) {
    throw new Error('Missing Temporal Cloud environment variables.');
  }

  const connection = await NativeConnection.connect({
    address,
    tls: true,
    apiKey,
  });

  return Worker.create({
    connection,
    namespace,
    taskQueue,
    workflowsPath: new URL('./workflows.js', import.meta.url).pathname,
    activities,
  });
}

import { Connection, Client } from '@temporalio/client';

const taskQueue = 'sub-ts';

function getEnv(name: string): string {
  const value = process.env[name];
  if (!value) {
    throw new Error(`Missing environment variable: ${name}`);
  }
  return value;
}

function delay(ms: number): Promise<void> {
  return new Promise((resolve) => {
    setTimeout(resolve, ms);
  });
}

export async function runClient(): Promise<void> {
  const address = getEnv('TEMPORAL_ADDRESS');
  const apiKey = getEnv('TEMPORAL_API_KEY');
  const namespace = getEnv('TEMPORAL_NAMESPACE');
  const runId = getEnv('ZEALT_RUN_ID');

  const connection = await Connection.connect({
    address,
    tls: true,
    apiKey,
  });

  const client = new Client({ connection, namespace });

  const handle = await client.workflow.start('SubscriptionWorkflow', {
    taskQueue,
    workflowId: `sub-${runId}`,
    args: [{ userId: 'u1', tier: 'basic' }],
  });

  await delay(1000);
  await handle.signal('upgrade', 'premium');

  await delay(2000);
  const status = await handle.query('getStatus');
  console.log(status);

  await delay(2000);
  await handle.signal('cancel');

  const result = await handle.result();
  console.log(`Final result: ${JSON.stringify(result)}`);
}

import { startWorker } from './worker.js';
import { runClient } from './client.js';

async function main() {
  const worker = await startWorker();
  const runPromise = worker.run();

  try {
    await runClient();
  } finally {
    worker.shutdown();
    await runPromise;
  }
}

main().catch((error) => {
  console.error(error);
  process.exitCode = 1;
});

